SELECT rooms.post_id, rooms.title, rooms.start_date, rooms.end_date, rooms.role, latest.content AS latest_message_content, latest.created_at AS latest_message_created_at, ( SELECT COUNT(*) FROM chat_messages unread LEFT JOIN chat_read_status crs ON crs.post_id = unread.post_id AND crs.user_id = #{userId} WHERE unread.post_id = rooms.post_id AND unread.user_id != #{userId} AND ( crs.last_read_at IS NULL OR unread.created_at > crs.last_read_at ) ) AS unread_count FROM ( SELECT p.id AS post_id, p.title, p.start_date, p.end_date, 'OWNER' AS role FROM posts p WHERE p.user_id = #{userId}
UNION
SELECT p.id AS post_id, p.title, p.start_date, p.end_date, 'COMPANION' AS role FROM companion_requests cr JOIN posts p ON cr.post_id = p.id WHERE cr.user_id = #{userId} AND cr.status = 'APPROVED' ) rooms LEFT JOIN chat_messages latest ON latest.id = ( SELECT cm.id FROM chat_messages cm WHERE cm.post_id = rooms.post_id ORDER BY cm.id DESC LIMIT 1 ) ORDER BY latest.created_at DESC, rooms.post_id DESC

SELECT COUNT(*)
FROM chat_messages cm
         LEFT JOIN chat_read_status crs
                   ON crs.post_id = cm.post_id
                       AND crs.user_id = #{userId}
WHERE cm.post_id = #{postId}
  AND cm.user_id != #{userId}
  AND (
      crs.last_read_at IS NULL
      OR cm.created_at > crs.last_read_at
  )

SELECT COUNT(*)
FROM chat_read_status
WHERE post_id = #{postId}
  AND user_id = #{userId}
